import{_ as d,o as a,c as e,ag as l}from"./chunks/framework.CAXxHpAX.js";const s=JSON.parse('{"title":"第 1 章 引言","description":"","frontmatter":{},"headers":[],"relativePath":"ml/basics.md","filePath":"ml/basics.md","lastUpdated":null}'),r={name:"ml/basics.md"};function i(h,t,o,p,c,n){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="第-1-章-引言" tabindex="-1">第 1 章 引言 <a class="header-anchor" href="#第-1-章-引言" aria-label="Permalink to &quot;第 1 章 引言&quot;">​</a></h1><p>这一章先回答三个问题：</p><ol><li>机器学习为什么重要？</li><li>什么是机器学习？</li><li>监督学习和无监督学习分别是什么？</li></ol><h2 id="_1-1-欢迎" tabindex="-1">1.1 欢迎 <a class="header-anchor" href="#_1-1-欢迎" aria-label="Permalink to &quot;1.1 欢迎&quot;">​</a></h2><p>机器学习已经成为信息技术里非常重要的方向。课程开头举了几个日常例子：</p><ul><li>搜索引擎根据学习算法对网页排序。</li><li>图片应用可以识别朋友的照片。</li><li>邮箱可以自动过滤垃圾邮件。</li><li>推荐系统可以根据用户行为推荐电影、商品或音乐。</li></ul><p>这门课不只是讲算法和数学，还强调自己实现算法。原因是：只知道公式不一定能解决实际问题，真正做机器学习时，还需要理解算法内部机制，并知道如何把算法用到具体场景中。</p><p>机器学习的应用范围很广，笔记中提到的方向包括：</p><table tabindex="0"><thead><tr><th>方向</th><th>例子</th></tr></thead><tbody><tr><td>数据挖掘</td><td>分析网站点击流、用户行为</td></tr><tr><td>医疗</td><td>从电子病历中总结疾病规律</td></tr><tr><td>计算生物学</td><td>分析基因、DNA 序列</td></tr><tr><td>工程</td><td>从越来越大的工程数据集中发现规律</td></tr><tr><td>自动控制</td><td>让无人直升机通过学习掌握飞行</td></tr><tr><td>手写识别</td><td>自动识别信封上的手写地址</td></tr><tr><td>自然语言处理</td><td>让机器理解文本</td></tr><tr><td>计算机视觉</td><td>让机器理解图像</td></tr><tr><td>推荐系统</td><td>Amazon、Netflix、iTunes 等推荐内容</td></tr></tbody></table><p>这一节的重点：机器学习的价值不只在人工智能本身，还在于它能让计算机从数据和经验中学习，而不是完全依赖人手写规则。</p><h2 id="_1-2-机器学习是什么" tabindex="-1">1.2 机器学习是什么？ <a class="header-anchor" href="#_1-2-机器学习是什么" aria-label="Permalink to &quot;1.2 机器学习是什么？&quot;">​</a></h2><p>课程里给了两个定义。</p><h3 id="arthur-samuel-的定义" tabindex="-1">Arthur Samuel 的定义 <a class="header-anchor" href="#arthur-samuel-的定义" aria-label="Permalink to &quot;Arthur Samuel 的定义&quot;">​</a></h3><p>Arthur Samuel 把机器学习理解为：在没有明确编程的情况下，让计算机具备学习能力。</p><p>他的例子是西洋棋程序。程序员自己不是高手，但让程序和自己下很多盘棋，从胜负中学习哪些棋盘局面更好，最后程序的下棋水平超过了作者。</p><p>这个定义比较直观：机器不是被逐条写死规则，而是通过经验提高表现。</p><h3 id="tom-mitchell-的定义" tabindex="-1">Tom Mitchell 的定义 <a class="header-anchor" href="#tom-mitchell-的定义" aria-label="Permalink to &quot;Tom Mitchell 的定义&quot;">​</a></h3><p>Tom Mitchell 的定义更适合考试和做笔记：</p><p>如果一个程序在任务 <code>T</code> 上，随着经验 <code>E</code> 的增加，经过性能度量 <code>P</code> 判断后表现有所提升，那么就说这个程序从经验 <code>E</code> 中学习。</p><p>可以拆成三个关键词：</p><table tabindex="0"><thead><tr><th>符号</th><th>含义</th><th>例子：西洋棋</th></tr></thead><tbody><tr><td><code>T</code></td><td>任务</td><td>下棋</td></tr><tr><td><code>E</code></td><td>经验</td><td>程序自己下了很多盘棋</td></tr><tr><td><code>P</code></td><td>性能度量</td><td>和新对手比赛时的胜率</td></tr></tbody></table><p>再看垃圾邮件过滤：</p><table tabindex="0"><thead><tr><th>符号</th><th>含义</th></tr></thead><tbody><tr><td><code>T</code></td><td>判断邮件是否为垃圾邮件</td></tr><tr><td><code>E</code></td><td>用户标记过的垃圾邮件和非垃圾邮件</td></tr><tr><td><code>P</code></td><td>过滤准确率等指标</td></tr></tbody></table><p>这一节还提到，课程主要讨论两类学习算法：</p><ul><li>监督学习：教计算机如何完成任务。</li><li>无监督学习：让计算机自己从数据中发现结构。</li></ul><p>课程后面也会涉及推荐系统、强化学习等内容，但最常用、最核心的是监督学习和无监督学习。</p><h2 id="_1-3-监督学习" tabindex="-1">1.3 监督学习 <a class="header-anchor" href="#_1-3-监督学习" aria-label="Permalink to &quot;1.3 监督学习&quot;">​</a></h2><p>监督学习的核心特征是：训练数据里包含“正确答案”。</p><p>也就是说，每个样本不只是有输入，还对应一个已知输出。算法根据这些样本学习规律，然后对新的输入做预测。</p><h3 id="例子-1-房价预测" tabindex="-1">例子 1：房价预测 <a class="header-anchor" href="#例子-1-房价预测" aria-label="Permalink to &quot;例子 1：房价预测&quot;">​</a></h3><p>输入是房屋面积，输出是房价。已知很多房子的实际成交价格后，希望预测一套新房子大概能卖多少钱。</p><p>这个任务属于回归问题。</p><p>回归问题要预测的是连续值，例如：</p><ul><li>房价</li><li>销量</li><li>温度</li><li>收入</li></ul><p>在房价例子中，可以用一条直线拟合数据，也可以用更复杂的曲线拟合数据。后续课程会讨论如何选择模型。</p><h3 id="例子-2-乳腺肿瘤判断" tabindex="-1">例子 2：乳腺肿瘤判断 <a class="header-anchor" href="#例子-2-乳腺肿瘤判断" aria-label="Permalink to &quot;例子 2：乳腺肿瘤判断&quot;">​</a></h3><p>输入可以是肿瘤大小、患者年龄、肿块密度、细胞大小一致性等特征，输出是肿瘤属于良性还是恶性。</p><p>这个任务属于分类问题。</p><p>分类问题要预测的是离散类别，例如：</p><ul><li>良性 / 恶性</li><li>垃圾邮件 / 非垃圾邮件</li><li>账号被盗 / 账号未被盗</li><li>癌症类型 0 / 1 / 2 / 3</li></ul><h3 id="回归和分类" tabindex="-1">回归和分类 <a class="header-anchor" href="#回归和分类" aria-label="Permalink to &quot;回归和分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>输出</th><th>课程例子</th></tr></thead><tbody><tr><td>回归</td><td>连续值</td><td>根据房屋面积预测房价</td></tr><tr><td>分类</td><td>离散类别</td><td>判断肿瘤是良性还是恶性</td></tr></tbody></table><p>监督学习小结：</p><ul><li>数据集中每个样本都有正确答案。</li><li>回归用于预测连续值。</li><li>分类用于预测离散类别。</li><li>特征可以只有一个，也可以有很多个。</li><li>后面会学到支持向量机等算法，用来处理更复杂的特征空间。</li></ul><h2 id="_1-4-无监督学习" tabindex="-1">1.4 无监督学习 <a class="header-anchor" href="#_1-4-无监督学习" aria-label="Permalink to &quot;1.4 无监督学习&quot;">​</a></h2><p>无监督学习的核心特征是：训练数据没有明确标签，也没有提前给出正确答案。</p><p>算法拿到的是一堆数据，需要自己从数据中发现结构。</p><h3 id="聚类" tabindex="-1">聚类 <a class="header-anchor" href="#聚类" aria-label="Permalink to &quot;聚类&quot;">​</a></h3><p>课程中首先介绍的是聚类算法。</p><p>聚类要做的是：把相似的数据自动分到同一组里。算法并不知道每一组应该叫什么，也没有人提前告诉它哪些样本属于同一类。</p><p>笔记中提到的聚类应用包括：</p><table tabindex="0"><thead><tr><th>场景</th><th>含义</th></tr></thead><tbody><tr><td>Google 新闻</td><td>把同一主题的新闻自动聚到一起</td></tr><tr><td>基因数据分析</td><td>根据基因表达情况把个体分组</td></tr><tr><td>大型计算机集群</td><td>分析哪些机器更适合协同工作</td></tr><tr><td>社交网络分析</td><td>根据朋友关系自动发现社交圈</td></tr><tr><td>市场细分</td><td>根据顾客数据自动划分不同消费群体</td></tr><tr><td>天文数据分析</td><td>从星系数据中发现结构</td></tr></tbody></table><p>这些问题都没有提前给出“正确分组”，所以属于无监督学习。</p><h3 id="鸡尾酒宴问题" tabindex="-1">鸡尾酒宴问题 <a class="header-anchor" href="#鸡尾酒宴问题" aria-label="Permalink to &quot;鸡尾酒宴问题&quot;">​</a></h3><p>无监督学习不只有聚类。课程还举了鸡尾酒宴问题：</p><p>一个房间里有多人同时说话，多个麦克风录到的是混合声音。算法需要从混合录音中分离出不同人的声音。</p><p>这个例子说明：合适的数学工具和编程环境可以让复杂算法的实现变得很短。课程因此推荐使用 Octave / Matlab 来快速搭建机器学习算法原型。</p><p>现在 Python 更常用，但这一节想强调的不是语言本身，而是：先用适合实验的工具快速验证算法，再考虑工程化实现。</p><h3 id="无监督学习小结" tabindex="-1">无监督学习小结 <a class="header-anchor" href="#无监督学习小结" aria-label="Permalink to &quot;无监督学习小结&quot;">​</a></h3><ul><li>无监督学习没有标签，也没有提前给出正确答案。</li><li>目标是从数据中自动发现结构。</li><li>聚类是无监督学习的重要类型。</li><li>聚类可以用于新闻分组、基因分析、社交网络、市场细分等任务。</li><li>鸡尾酒宴问题说明无监督学习还可以用于信号分离。</li></ul><h2 id="本章对比" tabindex="-1">本章对比 <a class="header-anchor" href="#本章对比" aria-label="Permalink to &quot;本章对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>数据特点</th><th>目标</th><th>例子</th></tr></thead><tbody><tr><td>监督学习</td><td>有正确答案 / 有标签</td><td>学会输入到输出的映射</td><td>房价预测、肿瘤分类、垃圾邮件过滤</td></tr><tr><td>无监督学习</td><td>没有正确答案 / 没标签</td><td>自动发现数据结构</td><td>新闻聚类、市场细分、基因聚类、声音分离</td></tr></tbody></table>',62)])])}const u=d(r,[["render",i]]);export{s as __pageData,u as default};
